import { useCallback } from 'react';

import Chip from '@mui/material/Chip';

import CrudResourceModule from 'features/shared/components/CrudResourceModule';
import useSelectOptions from 'features/shared/useSelectOptions';

const STATUS_OPTIONS = [
  { value: 'pending', label: 'Pendiente' },
  { value: 'in_progress', label: 'En curso' },
  { value: 'completed', label: 'Completada' },
  { value: 'overdue', label: 'Vencida' }
];

export default function ObjectivesPage() {
  const ownerLabelBuilder = useCallback((owner) => `${owner.parcel_code} - ${owner.full_name}`, []);
  const userLabelBuilder = useCallback((user) => `${user.username} (${user.role})`, []);

  const ownerOptions = useSelectOptions('/maps/parcel-options/', ownerLabelBuilder, { include_inactive: 'true' });
  const userOptions = useSelectOptions('/users/', userLabelBuilder);

  const columns = [
    { key: 'title', label: 'Objetivo' },
    { key: 'owner_parcel_code', label: 'Parcela' },
    { key: 'owner_display', label: 'Propietario' },
    { key: 'assigned_to_username', label: 'Responsable' },
    { key: 'due_date', label: 'Vencimiento' },
    {
      key: 'status',
      label: 'Estado',
      render: (row) => {
        const colorMap = {
          completed: 'success',
          in_progress: 'warning',
          overdue: 'error',
          pending: 'default'
        };
        return <Chip size="small" label={row.status} color={colorMap[row.status] || 'default'} />;
      }
    }
  ];

  const fields = () => [
    { name: 'owner', label: 'Parcela / Propietario', type: 'select', options: [{ value: '', label: 'Sin propietario' }, ...ownerOptions] },
    { name: 'assigned_to', label: 'Responsable', type: 'select', options: [{ value: '', label: 'Sin asignacion' }, ...userOptions] },
    { name: 'title', label: 'Titulo', required: true, fullWidth: true },
    { name: 'description', label: 'Descripcion', type: 'textarea', fullWidth: true },
    { name: 'latitude', label: 'Latitud', type: 'number' },
    { name: 'longitude', label: 'Longitud', type: 'number' },
    { name: 'due_date', label: 'Fecha limite', type: 'date' },
    { name: 'status', label: 'Estado', type: 'select', options: STATUS_OPTIONS, required: true }
  ];

  const mapPayload = (values) => ({
    ...values,
    owner: values.owner || null,
    assigned_to: values.assigned_to || null
  });

  return (
    <CrudResourceModule
      title="Objetivos Georreferenciados"
      path="/maps/objectives/"
      columns={columns}
      fields={fields}
      defaultOrdering="-created_at"
      mapPayload={mapPayload}
      searchPlaceholder="Buscar por titulo, descripcion o parcela..."
      extraFilters={[
        {
          key: 'status',
          label: 'Estado',
          options: STATUS_OPTIONS
        }
      ]}
    />
  );
}

